class DistributedSessionStore
  def initialize(app, options = {})
    @app = app
    @session_key = options[:key] || :session
  end

  def call(env)
    request = Rack::Request.new(env)
    
    session_cookie = request.cookies[@session_key.to_s]
    env['rack.session'] = restore_session(session_cookie)
    
    status, headers, body = @app.call(env)
    
    persist_session(env['rack.session'], headers)
    
    [status, headers, body]
  end

  private

  def restore_session(cookie_data)
    return {} unless cookie_data
    
    decoded = Base64.decode64(cookie_data)
    Marshal.load(decoded)
  rescue
    {}
  end

  def persist_session(session_data, headers)
    return if session_data.empty?
    
    serialized = Marshal.dump(session_data)
    encoded = Base64.encode64(serialized).gsub("\n", '')
    
    cookie = "#{@session_key}=#{encoded}; path=/; HttpOnly; SameSite=Lax"
    headers['Set-Cookie'] = cookie
  end
end

